mapper.select:
SELECT tenant_id, seller_company_id, buyer_company_id, credit_limit_amount, status, updated_at
FROM tb_buyer_credit_policy
WHERE tenant_id = #{tenantId}
  AND seller_company_id = #{sellerCompanyId}
  AND buyer_company_id = #{buyerCompanyId}

mapper.update:
UPDATE tb_buyer_credit_policy
SET credit_limit_amount = #{creditLimitAmount}
WHERE tenant_id = #{tenantId}
  AND seller_company_id = #{sellerCompanyId}
  AND buyer_company_id = #{buyerCompanyId}

mapper.select:
SELECT *
FROM tb_buyer_credit_ledger
WHERE tenant_id = #{tenantId}
  AND seller_company_id = #{sellerCompanyId}
  AND buyer_company_id = #{buyerCompanyId}
ORDER BY created_at DESC, credit_ledger_id DESC
LIMIT 1

SELECT *
FROM tb_buyer_advance_ledger
WHERE tenant_id = #{tenantId}
  AND seller_company_id = #{sellerCompanyId}
  AND buyer_company_id = #{buyerCompanyId}
ORDER BY created_at DESC, advance_ledger_id DESC
LIMIT 1
